// Product catalog with 4-dimensional hand-crafted vectors.
// Each dimension encodes a category affinity: [sports, tech, outdoor, home]
// In a real pipeline these vectors come from a text embedding model (e.g. LiteLLM).
// Note: Qdrant point IDs must be unsigned integers or UUIDs.
const products = [
  { id: 1, vector: [0.90, 0.10, 0.30, 0.10], payload: { name: 'Running Shoes',  category: 'Sports',      price: 89.99  } },
  { id: 2, vector: [0.80, 0.10, 0.40, 0.10], payload: { name: 'Trail Sneakers', category: 'Sports',      price: 110.00 } },
  { id: 3, vector: [0.10, 0.90, 0.10, 0.20], payload: { name: 'Laptop Stand',   category: 'Electronics', price: 45.00  } },
  { id: 4, vector: [0.20, 0.80, 0.10, 0.20], payload: { name: 'USB-C Hub',      category: 'Electronics', price: 35.00  } },
  { id: 5, vector: [0.50, 0.10, 0.90, 0.10], payload: { name: 'Hiking Backpack',category: 'Outdoors',    price: 129.99 } },
  { id: 6, vector: [0.10, 0.20, 0.10, 0.90], payload: { name: 'Scented Candle', category: 'Home',        price: 24.99  } },
];
// Query: 'sporty outdoor item' → high sports + outdoor affinity
const queryVector = [0.85, 0.10, 0.35, 0.10];
return [{ json: { products, queryVector, collection: 'qdrant_demo' } }];

const hits = $input.item.json.result || [];
const query = $('Sample Data').item.json.queryVector;
const formatted = hits.map((h, i) => ({
  rank: i + 1,
  score: Math.round(h.score * 1000) / 1000,
  name: h.payload.name,
  category: h.payload.category,
  price: `$${h.payload.price}`,
}));
return [{ json: {
  description: 'Top-3 Qdrant similarity results for query vector (sporty outdoor item)',
  queryVector: query,
  results: formatted,
} }];
